'use server';

import { updateTag } from 'next/cache';

export type Post = {
  id: number;
  title: string;
  createdAt: string;
};

const globalStore = globalThis as typeof globalThis & {
  __posts?: Post[];
};

function getPostStore() {
  if (!globalStore.__posts) {
    globalStore.__posts = [
      {
        id: 1,
        title: 'Hello from the cache',
        createdAt: new Date('2026-01-01T12:00:00.000Z').toISOString()
      }
    ];
  }

  return globalStore.__posts;
}

export async function getPosts(): Promise<Post[]> {
  'use cache';
  cacheTag('posts');

  return [...getPostStore()].sort((a, b) => b.id - a.id);
}

export async function createPost(formData: FormData) {
  const title = String(formData.get('title') ?? '').trim();

  if (!title) {
    throw new Error('Title is required.');
  }

  const posts = getPostStore();
  const nextId = posts.length ? Math.max(...posts.map((post) => post.id)) + 1 : 1;

  posts.push({
    id: nextId,
    title,
    createdAt: new Date().toISOString()
  });

  updateTag('posts');
}

import { createPost, getPosts } from './actions';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main
      style={{
        fontFamily: 'Arial, sans-serif',
        maxWidth: 720,
        margin: '0 auto',
        padding: '3rem 1.5rem'
      }}
    >
      <h1>Posts</h1>
      <p>
        Create a post with a Server Action. The posts query is cached with the <code>posts</code>{' '}
        tag and is refreshed immediately after creation.
      </p>

      <form action={createPost} style={{ display: 'grid', gap: '0.75rem', marginTop: '1.5rem' }}>
        <label htmlFor="title" style={{ fontWeight: 600 }}>
          Title
        </label>
        <input
          id="title"
          name="title"
          type="text"
          placeholder="Write a new post title"
          required
          style={{ padding: '0.75rem', fontSize: '1rem' }}
        />
        <button
          type="submit"
          style={{
            width: 'fit-content',
            padding: '0.75rem 1rem',
            fontSize: '1rem',
            cursor: 'pointer'
          }}
        >
          Create post
        </button>
      </form>

      <section style={{ marginTop: '2rem' }}>
        <h2>All posts</h2>
        <ul style={{ paddingLeft: '1.25rem' }}>
          {posts.map((post) => (
            <li key={post.id} style={{ marginBottom: '0.75rem' }}>
              <strong>{post.title}</strong>
              <br />
              <small>
                #{post.id} · {new Date(post.createdAt).toLocaleString()}
              </small>
            </li>
          ))}
        </ul>
      </section>
    </main>
  );
}

